var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그림자 전당으로 가신다고요?","JPN":"影の殿堂へ行くのですか？","ENG":"You're heading to the Shadow Palace?","TWN":"要去暗影殿堂？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"로터스의 대균열이 가장 안전한 진입루트라곤 하지만 고심도는 고심도입니다. 그림자 전당은 이웃집이 아녜요.","JPN":"ロータスの大亀裂が一番安全な進入ルートといっても、高深度には変わりません。影の殿堂は気軽に行ける場所ではないのです。","ENG":"Although Lotus' Grand Dimension Crevice is the safest route there, the hyperdepth is still the hyperdepth. The Shadow Palace isn't your next-door neighbor's house.","TWN":"洛德斯的大峽谷雖然是最安全的路線，但畢竟也是高深度地帶。暗影殿堂沒那麼容易出入。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지난 번에도 몇 번씩이나 목숨이 위험하셨을 텐데요? 차라리 제가 갈 테니 기다리시죠.","JPN":"この前も命が危なかった瞬間が何度もありましたよね？私が行きますから、待っていてください。","ENG":"Even last time, you almost died a few times. I'll go instead, so wait for me.","TWN":"你過去也不是冒過幾次生命危險嗎？為什麼不等我過去呢？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아스널 윙 없이는 제때 도착하기 힘들 걸세. 자네는 아직 클리포트 게임의 뒷수습도 마무리 짓지 못한 상태잖나.","JPN":"アーセナルウイングがなければ間に合わないだろう。君はまだクリフォトゲームの後始末も残っているのではないか？","ENG":"It'll be hard to arrive on time without your Arsenal Wings. Plus, you're still caught up with cleaning up the mess from the Qliphoth Game.","TWN":"沒有軍火之翼，你很難及時趕到。而且你還沒有處理完逆卡巴拉遊戲的善後。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고, 적어도 난 도플갱어를 만날 일이 없으니 한시름 던 셈이지.","JPN":"それに、少なくとも私はドッペルゲンガーに会う可能性がないから、心配しなくてもいい。","ENG":"Also, it's better I go because I won't have to meet my doppelganger, at least.","TWN":"而且，我至少不用擔心遇到二重身。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"방금 그걸 농담이라고 하신 건가요?","JPN":"今のは冗談のつもりですか？","ENG":"Is that supposed to be a joke?","TWN":"你剛才是在開玩笑嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미안하게 됐군. 자네들이 어렵게 돌려받은 평화인데, 그리 오래가진 못하겠어.","JPN":"申し訳ない。君たちが頑張って取り戻した平和なのに、そう長くは持たなそうだ。","ENG":"You guys fought so hard to get back peace, and I'm sorry it didn't last long.","TWN":"抱歉，你們辛苦找回的和平馬上就要被瓦解了。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양은… 별말 없이 동행하겠다고 하던가요?","JPN":"ミナさんは……何も言わずに同行すると言ったのですか？","ENG":"Is Mina... accompanying you without saying anything?","TWN":"米娜她……二話不說就要和你同行？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래, 나를 위한 결정은 아니지만 지금은 함께 해주는 걸로도 고마운 일이지.","JPN":"そう、私のためではないが、今は一緒にいるだけでもありがたい。","ENG":"Yes. Although she's not doing it for me, I'm grateful to have her by my side.","TWN":"是的，雖然她這麼做並不是為了我，但我還是很感激能有她的陪伴。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…말씀하신 대로, 그림자 전당 최심부까지 향하는 최단거리 좌표를 전송해드렸습니다.","JPN":"……おっしゃったとおりに、影の殿堂の最深部まで行く最短距離の座標を転送いたしました。","ENG":"...As you requested, I've sent you the coordinates for the shortest route to the deepest part of the Shadow Palace.","TWN":"……按你的吩咐，我已經把通往暗影殿堂最深處的最短距離座標發給你了。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 정도면 민간 비행선도 그림자 전당까지 무사히 진입할 순 있겠죠.","JPN":"このくらいなら民間の飛行船でも影の殿堂まで無事に侵入できるでしょう。","ENG":"I believe even a commercial aircraft can reach the Shadow Palace safely.","TWN":"這麼一來，乘坐民用飛船也應該足以安全進入暗影殿堂。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어디까지나 진입한 뒤가 문제지만요.","JPN":"進入した後が問題ですが。","ENG":"But the problem is after arriving there, I suppose.","TWN":"唯一的問題是在到達之後。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고맙군, 부사장.","JPN":"ありがとう、副社長。","ENG":"Thank you, Vice President.","TWN":"謝謝你，副總。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 조심하세요.","JPN":"でも、気を付けてください。","ENG":"But be careful.","TWN":"但要小心。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그자가 방주를 건드렸다면 그곳의 보안 시스템도 정상은 아닐 겁니다.","JPN":"あの者が箱舟に触れたのなら、きっとセキュリティーシステムも正常ではないはずです。","ENG":"If she has already tampered with the Ark, the security system over there won't be normal.","TWN":"如果她動了方舟，那裡的安全系統可能也已經失常了。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>로터스 대균열 고심도, 그림자 전당. 코핀-6. 클리파 에너지 미량 유출 감지.</color>","JPN":"<color=#ffd34c>ロータスの大亀裂、高深度、影の殿堂。コフィン-6。微量のクリファエネルギーの流出を感知。</color>","ENG":"<color=#ffd34c>Lotus Grand Dimension Crevice Hyperdepths, Shadow Palace. Coffin-6. Small traces of Qlipha energy detected.</color>","TWN":"<color=#ffd34c>洛德斯大峽谷高深度，暗影殿堂。科芬-6.發現微量的逆卡巴拉能量洩漏痕跡。</color>","THA":"<color=#ffd34c>ความลึกของรอยแยกโลตัสแกรนด์ไดเมนชั่น วังแชโดว์ คอฟฟิน-6 ตรวจพบร่องรอยเล็กๆ ของพลังงานคลิฟ่า</color>","VTN":"<color=#ffd34c>Tầng siêu sâu của Khe Nứt Không Gian Vĩ Đại Lotus, Cung Điện Bóng Tối. Coffin-6: Phát hiện dấu vết rò rỉ năng lượng của Qlipha. </color>","SCN":"<color=#ffd34c>洛德斯大裂谷高深度区域，暗影殿堂。科芬-6。发现微量逆卡巴拉能量泄漏痕迹。</color>","DEU":"<color=#ffd34c>Hypertiefen der Dimensionskluft von Lotus, Schattenpaläste. Coffin-6. Erkennung von kleinen Klippa-Energielecks.</color>","FRA":"<color=#ffd34c>Hyperprofondeurs de la Crevasse de grande dimension de Lotus, Palais des ombres. Coffin-6. Fuites infimes d'énergie Qlipha détectées.</color>"},"stage":{"bg":"black","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};